<?php
namespace App\Http\Controllers;
use App\Models\User; use App\Models\Citoyen; use Illuminate\Http\Request; use Illuminate\Support\Facades\Hash; use Illuminate\Support\Facades\DB;
class AuthController extends Controller{
public function showLogin(){return view('auth.login');} public function showRegister(){return view('auth.register');}
public function login(Request $r){$d=$r->validate(['email'=>'required|email','password'=>'required']);$u=User::where('email',$d['email'])->where('statut','actif')->first();if(!$u||!Hash::check($d['password'],$u->password))return back()->withErrors(['email'=>'Identifiants incorrects.'])->withInput();session(['user_id'=>$u->id,'name'=>$u->name,'email'=>$u->email,'role'=>$u->role,'ministere_id'=>$u->ministere_id,'service_interne_id'=>$u->service_interne_id]);return match($u->role){'citoyen'=>redirect()->route('citoyen.dashboard'),'agent_public'=>redirect()->route('agent.dashboard'),default=>redirect()->route('admin.dashboard')};}
public function register(Request $r){$d=$r->validate(['nom'=>'required|max:120','prenom'=>'required|max:120','email'=>'required|email|max:191|unique:users,email','telephone'=>'required|max:60','nni'=>'required|max:80|unique:citoyens,nni','date_naissance'=>'required|date','password'=>'required|confirmed|min:6']);DB::transaction(function()use($r,$d){$u=User::create(['name'=>$d['nom'].' '.$d['prenom'],'email'=>$d['email'],'password'=>Hash::make($d['password']),'role'=>'citoyen','statut'=>'actif']);Citoyen::create(['user_id'=>$u->id,'nni'=>$d['nni'],'nom'=>$d['nom'],'prenom'=>$d['prenom'],'telephone'=>$d['telephone'],'email'=>$d['email'],'date_naissance'=>$d['date_naissance'],'nationalite'=>'Centrafricaine']);});return redirect()->route('login')->with('success','Compte citoyen créé.');}
public function logout(Request $r){$r->session()->flush();return redirect()->route('home');}}
